<?php get_header(); ?><section class="content-page section"><p class="eyebrow"><?php echo esc_html( olga_t( 'search' ) ); ?></p><h1><?php echo esc_html( olga_t( 'search_results', get_search_query() ) ); ?></h1><?php if ( have_posts() ) : while ( have_posts() ) : the_post(); ?><article><h2><a href="<?php echo esc_url( olga_url( get_permalink() ) ); ?>"><?php echo esc_html( olga_post_value( get_the_ID(), 'title' ) ); ?></a></h2><?php echo esc_html( olga_post_value( get_the_ID(), 'excerpt' ) ); ?></article><?php endwhile; else : ?><p><?php echo esc_html( olga_t( 'nothing_found' ) ); ?></p><?php endif; ?></section><?php get_footer(); ?>
